//parcel.js

// src/pages/Parcel.js
import React, { useState, useEffect } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Box,
  MenuItem,
} from "@mui/material";
import {
  MapContainer,
  TileLayer,
  Marker,
  Popup,
  useMapEvents,
} from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

export default function Parcel() {
  const [form, setForm] = useState({
    senderName: "",
    senderMobile: "",
    receiverName: "",
    receiverMobile: "",
    parcelCategory: "",
    parcelDetails: "",
    pickupAddress: "",
    dropAddress: "",
  });

  const [pickup, setPickup] = useState(null); // {lat, lng}
  const [drop, setDrop] = useState(null);
  const [currentLocation, setCurrentLocation] = useState(null);

  // 📍 Get current location
  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      (pos) =>
        setCurrentLocation({
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
        }),
      (err) => console.error("Geolocation error:", err)
    );
  }, []);

  const handleChange = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("📦 Parcel Request:", { ...form, pickup, drop });
    alert("Parcel request submitted! (connect to backend)");
  };

  // 📍 Marker select component
  function LocationMarker({ type }) {
    useMapEvents({
      click(e) {
        if (type === "pickup") setPickup(e.latlng);
        if (type === "drop") setDrop(e.latlng);
      },
    });
    return null;
  }

  // ✅ Custom marker icons
  const pickupIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/32/32339.png", // 🟢 Green dot
    iconSize: [25, 25],
    iconAnchor: [12, 12],
  });

  const dropIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/684/684908.png", // 🔴 Red pin
    iconSize: [35, 35],
    iconAnchor: [17, 34],
  });

  const currentIcon = new L.DivIcon({
  className: "custom-blue-dot",
  html: `<div style="
      width: 16px;
      height: 16px;
      background: blue;
      border-radius: 50%;
      border: 2px solid white;
      box-shadow: 0 0 5px rgba(0,0,0,0.3);
    "></div>`,
  iconSize: [16, 16],
  iconAnchor: [8, 8],
});

 return (
  <Container maxWidth="lg">
    <Paper sx={{ mt: 4, p: 4, borderRadius: 3 }}>
      <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
        📦 Book a Parcel
      </Typography>
      <Typography variant="body2" sx={{ mb: 3, color: "gray" }}>
        Fill in the parcel details and select pickup/drop points (manual or map).
      </Typography>

      {/* ✅ Flex layout: Form (left) + Map (right) */}
      <Box
        sx={{
          display: "grid",
          gridTemplateColumns: { xs: "1fr", md: "1fr 1fr" }, // stack on mobile, side-by-side on desktop
          gap: 3,
        }}
      >
        {/* --- LEFT: Form --- */}
        <Box
          component="form"
          onSubmit={handleSubmit}
          sx={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: 2,
          }}
        >
          <TextField
            name="senderName"
            label="Sender Name"
            value={form.senderName}
            onChange={handleChange}
            required
          />
          <TextField
            name="senderMobile"
            label="Sender Mobile"
            value={form.senderMobile}
            onChange={handleChange}
            required
          />
          <TextField
            name="receiverName"
            label="Receiver Name"
            value={form.receiverName}
            onChange={handleChange}
            required
          />
          <TextField
            name="receiverMobile"
            label="Receiver Mobile"
            value={form.receiverMobile}
            onChange={handleChange}
            required
          />

          {/* Parcel Category */}
          <TextField
            select
            name="parcelCategory"
            label="Parcel Category"
            value={form.parcelCategory}
            onChange={handleChange}
            required
            sx={{ gridColumn: "1/3" }}
          >
            <MenuItem value="Documents">Documents</MenuItem>
            <MenuItem value="Food">Food</MenuItem>
            <MenuItem value="Electronics">Electronics</MenuItem>
            <MenuItem value="Clothes">Clothes</MenuItem>
            <MenuItem value="Fragile">Fragile</MenuItem>
            <MenuItem value="Other">Other</MenuItem>
          </TextField>

          {/* Manual Pickup / Drop */}
          <TextField
            name="pickupAddress"
            label="Pickup Address (manual)"
            value={form.pickupAddress}
            onChange={handleChange}
            fullWidth
            sx={{ gridColumn: "1/3" }}
          />
          <TextField
            name="dropAddress"
            label="Drop Address (manual)"
            value={form.dropAddress}
            onChange={handleChange}
            fullWidth
            sx={{ gridColumn: "1/3" }}
          />

          <TextField
            name="parcelDetails"
            label="Parcel Details"
            value={form.parcelDetails}
            onChange={handleChange}
            fullWidth
            multiline
            rows={2}
            sx={{ gridColumn: "1/3" }}
          />

          <Button
            type="submit"
            variant="contained"
            sx={{
              mt: 2,
              gridColumn: "1/3",
              bgcolor: "black",
              "&:hover": { bgcolor: "#333" },
            }}
          >
            Submit Parcel Request
          </Button>
        </Box>

        {/* --- RIGHT: Map --- */}
        <Box sx={{ height: "100%", minHeight: "500px", borderRadius: 2, overflow: "hidden" }}>
          {currentLocation && (
            <MapContainer
              center={currentLocation}
              zoom={13}
              style={{ height: "100%", width: "100%" }}
            >
              <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/">OSM</a>'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              />

              {/* Current Location */}
              <Marker position={currentLocation} icon={currentIcon}>
                <Popup>You are here</Popup>
              </Marker>

              {/* Pickup */}
              {pickup && (
                <Marker position={pickup} icon={pickupIcon}>
                  <Popup>Sender (Pickup)</Popup>
                </Marker>
              )}
              <LocationMarker type="pickup" />

              {/* Drop */}
              {drop && (
                <Marker position={drop} icon={dropIcon}>
                  <Popup>Receiver (Drop)</Popup>
                </Marker>
              )}
              <LocationMarker type="drop" />
            </MapContainer>
          )}
        </Box>
      </Box>
    </Paper>
  </Container>
);

}
